var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"시공간 수정의 후유증은 꽤나 다양해, 친구.","JPN":"時空間修正の後遺症は、かなり様々だ。","ENG":"Side effects of spacetime recalibration are quite diverse, my friend.","TWN":"修正時空會引起多種後遺症，朋友。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특히나 자네처럼 많이 겪은 경우에는...... 무슨 일이 일어날지 장담할 수 없어.","JPN":"特に君のように、色んなことがあった場合……何が起きるかわからない。","ENG":"And for someone who has done it multiple times like yourself, there's no telling what might happen.","TWN":"特別是像你這種經歷了很多次的情況……我無法保證會發生什麼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 자네의 길잡이로서, 이것 하나는 얘기해 줄 수 있겠군.","JPN":"だが、君のガイドとして、これだけは言える。","ENG":"But as your guide, I can tell you this.","TWN":"但作為你的領路人，我可以告訴你一點。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈에서 다른 사람과 눈을 마주치게 되더라도 너무 놀라진 마. 그건 실제가 아니고, 그들의 추억을 잠시 관측하는 것 뿐이니까.","JPN":"夢の中で他の人と目が合っても、あまり驚くな。それは現実ではなく、彼らの思い出を少し観察するにすぎない。","ENG":"Don't be too surprised if you get to make eye contact with someone else. It's not real. You're observing their memories for a short period of time.","TWN":"在夢裡，即使與他人對上視線也不要太驚訝。因為那並不是現實，你只是在暫時觀看他們的回憶而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사람들의 행복했던 시절을 함께 돌아보는 것도...... 자네가 앞으로 걸을 길에 작은 위안 정도는 되겠지.","JPN":"だが、誰かの幸せだった時期を一緒に振り返るのも……これから君が歩むべき道の、小さな癒しにはなるだろう。","ENG":"But looking back at people's memories of their happy past could provide some comfort for your mind while walking the path you're on.","TWN":"不過，與他人一同觀看幸福的回憶……或許能在你前行的道路上，成為小小的慰藉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"좋아~ 감자칩도 에너지드링크도 준비 완료~","JPN":"よ～し、ポテチとエナジードリンク、準備完了～。","ENG":"Chips, check. Energy drink, check.","TWN":"好～薯片和能量飲料都準備好了～"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"자~ 오늘은 또 어떤 자신만만한 친구들을 골려 보실까?","JPN":"さてと～今日は、誰をからかおうかな？","ENG":"Now, which arrogant fools should I pick on today?","TWN":"嗯～今天該挑選哪位自信滿滿的朋友呢？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"어디 보자, 랭글리는 다시 찾아가 봐야 김빠지니까......","JPN":"どれどれ。ラングリーは、もうつまらないし……","ENG":"Let's see. Langley's out. There's no point doing it again.","TWN":"讓我看看，再找蘭利就太掃興了……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"좋았어. 오늘은 아껴 두고 있었던 관리국 데이터베이스에 한 번 도전해 보실까.","JPN":"よし。今日は、管理局のデータベースに挑戦しよう。","ENG":"Alright. It's going to be the Administration's database today. I've been saving it for a time like this.","TWN":"很好。今天就挑戰一下珍藏已久的管理局資料庫吧。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"보안이 꽤 철저하다지만...... 휘스턴 할머니네 뒤뜰 담장보다 넘기 어렵겠어?","JPN":"セキュリティが、かなりしっかりしてるって噂だけど……ヒューストンさんの裏庭の塀を越えるより簡単でしょ。","ENG":"They say they're well guarded, but I doubt it'd be harder than climbing over the fence of Mrs. Whiston's house.","TWN":"雖說保全系統非常完善……但不可能比惠斯頓奶奶家的圍牆還要難翻吧？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"자아, 사이버캣의 보안 교실~ 시작해 보실까~","JPN":"さあ、サイバーキャットのセキュリティ教室～始まり～","ENG":"Cyber Cat's IT Security 101 starts... now.","TWN":"好的，賽博貓的保全課堂~開始啦~"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"......응?","JPN":"……あれ？","ENG":"Huh?","TWN":"……嗯！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"뭐야, 선객이 있었잖아?","JPN":"先客がいたのね。","ENG":"There's already someone trying to break into the system.","TWN":"什麼，已經有人捷足先登了？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"에휴, 이렇게 자기 쳐들어왔다고 광고하는 녀석들 때문에 나까지 욕을 먹잖아.","JPN":"はあ、侵入しましたって自慢するやつらのせいで、アタシまで叩かれるじゃない。","ENG":"And this guy's clumsy as heck. It's these types of people that give everyone in the business a bad name.","TWN":"唉，就是因為這種侵入後還要到處宣傳的傢伙，害得我也要被罵。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"사이버캣은 횡단보도 건널 때 손 들고 다니는 모범시민~ 신고합니다~","JPN":"サイバーキャットは横断歩道を渡る時、手を上げて渡るいい子なので～通報するね～","ENG":"Cyber Cat is an exemplary citizen who never forgets to raise hands when crossing the road. I'm reporting you.","TWN":"賽博貓是一個過斑馬線時都會舉手示意的模範市民~特此申告~"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"슝~ 보안팀에 메시지 넣었고~","JPN":"は～い、セキュリティチームに、メッセージを送ったから～","ENG":"Swoosh! The message has been sent to the security team.","TWN":"咻～已經將資訊投給保全團隊了～"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"다섯, 넷, 셋……","JPN":"ご、よん、さん……","ENG":"Let's see... Five, four, three...","TWN":"五，四，三……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"둘......","JPN":"に……","ENG":"two...","TWN":"二……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_CHILD","text":{"KOREA":"하나.","JPN":"いち。","ENG":"one.","TWN":"一。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};